import React, { useState } from 'react';

const Contact = () => {
  const [msg, setMsg] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    alert("तुमचा मेसेज प्राप्त झाला आहे! आम्ही लवकरच संपर्क करू.");
  };

  return (
    <div style={styles.container}>
      <h1 style={{color: '#00d2ff'}}>Contact Support</h1>
      <p>काही अडचण असल्यास आम्हाला कळवा.</p>
      <form onSubmit={handleSubmit} style={styles.form}>
        <input type="text" placeholder="तुमचे नाव" required style={styles.input} />
        <input type="email" placeholder="तुमचा ईमेल" required style={styles.input} />
        <textarea placeholder="तुमचा मेसेज..." required style={{...styles.input, height: '100px'}} />
        <button type="submit" style={styles.btn}>मेसेज पाठवा</button>
      </form>
    </div>
  );
};

const styles = {
  container: { background: '#000', color: '#fff', padding: '100px', textAlign: 'center', minHeight: '100vh' },
  form: { maxWidth: '400px', margin: '30px auto', display: 'flex', flexDirection: 'column', gap: '15px' },
  input: { padding: '12px', borderRadius: '5px', border: '1px solid #333', background: '#111', color: '#fff' },
  btn: { background: '#00d2ff', color: '#000', padding: '12px', border: 'none', borderRadius: '5px', fontWeight: 'bold', cursor: 'pointer' }
};

export default Contact;
